--
-- Name: sync_inventory_sku_stock_to_variants(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.sync_inventory_sku_stock_to_variants() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
    begin
      update product_variants
         set stock = new.stock,
             updated_at = now()
       where inventory_sku_id = new.id
         and stock is distinct from new.stock;
      return new;
    end;
    $$;


ALTER FUNCTION public.sync_inventory_sku_stock_to_variants() OWNER TO postgres;

--
-- Name: sync_products_status_and_active(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.sync_products_status_and_active() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
        begin
          if new.status is null or btrim(new.status) = '' then
            new.status := case when coalesce(new.is_active, false) = true then 'active' else 'inactive' end;
          else
            new.status := lower(new.status);
            if new.status = 'active' then
              new.is_active := true;
            elsif new.status in ('inactive', 'pending', 'rejected') then
              new.is_active := false;
            else
              raise exception 'invalid products.status: %', new.status;
            end if;
          end if;
          return new;
        end;
        $$;


ALTER FUNCTION public.sync_products_status_and_active() OWNER TO postgres;

--
-- Name: sync_variant_stock_to_inventory_skus(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.sync_variant_stock_to_inventory_skus() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
    begin
      if new.inventory_sku_id is null then
        return new;
      end if;

      if tg_op = 'UPDATE'
         and new.inventory_sku_id = old.inventory_sku_id
         and new.stock is not distinct from old.stock then
        return new;
      end if;

      update inventory_skus
         set stock = greatest(new.stock, 0),
             updated_at = now()
       where id = new.inventory_sku_id
         and stock is distinct from greatest(new.stock, 0);
      return new;
    end;
    $$;


ALTER FUNCTION public.sync_variant_stock_to_inventory_skus() OWNER TO postgres;

